import React, { useState } from "react";
import { ChevronLeft, Banknote, Lock } from "lucide-react";
import { useCurrency } from "../context/CurrencyContext";

export default function DepositScreen({
  onBack,
  onConfirm,
  openAddPaymentSource,
}) {
  const { formatAmount } = useCurrency();

  const [amount, setAmount] = useState("");
  const [duration, setDuration] = useState(3);
  const [sourceAccount, setSourceAccount] = useState("Access Bank - **** 1234");

  const numericAmount = Number(amount);
  const isValidAmount = numericAmount > 0 && !Number.isNaN(numericAmount);

  const calculateWithdrawalDate = (months) => {
    const date = new Date();
    date.setMonth(date.getMonth() + months);
    return date;
  };

  const handleConfirm = () => {
    if (!isValidAmount) return;

    const startDate = new Date();
    const withdrawalDate = calculateWithdrawalDate(duration);

    onConfirm({
      amount: numericAmount,
      durationMonths: duration,
      startDate: startDate.toISOString(),
      withdrawalDate: withdrawalDate.toISOString(),
      source: sourceAccount,
    });
  };

  return (
    <div className="flex flex-col bg-white animate-in slide-in-from-right duration-300 h-full">

      {/* Header */}
      <div className="flex items-center gap-3 px-6 py-4 sticky top-0 bg-white z-10">
        <button
          onClick={onBack}
          className="p-2 hover:bg-gray-100 rounded-full"
        >
          <ChevronLeft className="w-6 h-6 text-gray-800" />
        </button>
        <h1 className="text-xl font-bold text-gray-900">
          Lock Your Savings
        </h1>
      </div>

      {/* Content */}
      <div className="p-6 flex-1">

        {/* Lock Info */}
        <div className="bg-emerald-50 p-6 rounded-[2.5rem] mb-8 border border-emerald-100">
          <div className="flex items-center gap-2 mb-2 text-emerald-700 font-bold">
            <Lock size={18} />
            Locked Savings
          </div>
          <p className="text-sm text-emerald-700">
            Your money will be locked until the selected withdrawal date.
            Early withdrawal is not allowed.
          </p>
        </div>

        {/* Amount */}
        <div className="space-y-2 mb-6">
          <label className="text-sm font-bold text-gray-700 ml-1">
            Amount to Save
          </label>
          <div className="relative">
            <Banknote className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-gray-400" />
            <input
              type="number"
              inputMode="numeric"
              value={amount}
              onChange={(e) => setAmount(e.target.value)}
              placeholder={formatAmount(0)}
              className="w-full p-4 pl-12 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] text-lg font-bold"
            />
          </div>
        </div>

        {/* Duration */}
        <div className="space-y-3 mb-6">
          <label className="text-sm font-bold text-gray-700 ml-1">
            Savings Duration
          </label>

          <div className="grid grid-cols-3 gap-3">
            {[3, 6, 12].map((m) => (
              <button
                key={m}
                onClick={() => setDuration(m)}
                className={`py-3 rounded-xl font-bold transition
                  ${
                    duration === m
                      ? "bg-[#00875A] text-white"
                      : "bg-gray-100 text-gray-700"
                  }
                `}
              >
                {m} months
              </button>
            ))}
          </div>
        </div>

        {/* Source Account */}
        <div className="space-y-2">
          <label className="text-sm font-bold text-gray-700 ml-1">
            Payment Source
          </label>
          <select
            value={sourceAccount}
            onChange={(e) => setSourceAccount(e.target.value)}
            className="w-full p-4 rounded-2xl bg-gray-50 border border-gray-100 outline-none focus:border-[#00875A] font-medium"
          >
            <option>Access Bank - **** 1234</option>
            <option>GTBank - **** 5678</option>
            <option value="add-new">Add New Bank Card</option>
          </select>
        </div>
      </div>

      {/* Add Bank */}
      <p className="text-center text-gray-400 text-sm mb-4">
        Don&apos;t see your card?{" "}
        <button
          className="text-[#00875A] font-black cursor-pointer"
          onClick={() => openScreen("AddPaymentSource")}>
          Add New Card
        </button>
      </p>

      {/* Confirm */}
      <div className="pb-10 flex justify-center">
        <button
          onClick={handleConfirm}
          disabled={!isValidAmount}
          className={`w-[90%] py-4 rounded-2xl font-bold text-white shadow-xl transition-all
            ${
              isValidAmount
                ? "bg-[#00875A] shadow-emerald-100 active:scale-95"
                : "bg-gray-300 cursor-not-allowed"
            }
          `}
        >
          Lock Savings
        </button>
      </div>
    </div>
  );
}
